class Solution:
    def maximumScore(self, nums, s):
        ones = [i for i, c in enumerate(s) if c == '1']
        k = len(ones)
        if k == 0:
            return 0
        r_last = ones[-1]
        NEG = float('-inf')
        dp = [NEG] * (k + 1)
        dp[0] = 0
        ptr = 0
        for i in range(r_last + 1):
            new_dp = dp[:]
            for j in range(k, 0, -1):
                if dp[j - 1] != NEG:
                    cand = dp[j - 1] + nums[i]
                    if cand > new_dp[j]:
                        new_dp[j] = cand
            dp = new_dp
            if ptr < k and ones[ptr] == i:
                m = ptr + 1
                for j in range(0, m):
                    dp[j] = NEG
                ptr += 1
        return dp[k]

