var maximumScore = function(nums, s) {
    const n = nums.length;
    const ones = [];
    for (let i = 0; i < n; i++) if (s[i] === '1') ones.push(i);
    const k = ones.length;
    if (k === 0) return 0;
    const rLast = ones[ones.length - 1];
    const parent = new Array(k + 1);
    for (let i = 0; i <= k; i++) parent[i] = i;
    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    function bisectLeft(target) {
        let lo = 0, hi = ones.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (ones[mid] < target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    const items = [];
    for (let i = 0; i <= rLast; i++) items.push(i);
    items.sort((a, b) => nums[b] - nums[a]);
    let total = 0, count = 0;
    for (const i of items) {
        const idx = bisectLeft(i);
        const slot = find(idx);
        if (slot < k) {
            total += nums[i];
            parent[slot] = slot + 1;
            count++;
            if (count === k) break;
        }
    }
    return total;
};
